  array('Yarn'=>21,'Chi'=>142, 'Extend_Duration'=>'An Age (~500,000 Years)', 'Limit_Duration'=>'30 Secs', 'Group_Size'=>'Thousands of Millions / Billions (<5,000,000,000)', 'Smaller_Size'=>'(~1.0 &times;10<sup>-24</sup>metres)','Location_Size'=>'Continent / Enormous Ecoregion (Arctic / Antarctic) / Small Moon / Vehicle (Rising Sun / Lord of Heaven)'),
  array('Yarn'=>22,'Chi'=>153, 'Extend_Duration'=>'~1,000,000 Years', 'Limit_Duration'=>'15 Secs', 'Group_Size'=>'Tens of Billions (<20,000,000,000)', 'Smaller_Size'=>'(~1.0 &times;10<sup>-25</sup>metres)','Location_Size'=>'Small Planet, or Moon / Vehicle (Worm Freighter)'),
  array('Yarn'=>23,'Chi'=>165, 'Extend_Duration'=>'~5,000,000 Years', 'Limit_Duration'=>'7 Secs', 'Group_Size'=>'A Hundred, Thousand, Million /Hundred Billion (<100,000,000,001)', 'Smaller_Size'=>'(~1.0 &times;10<sup>-26</sup>metres)','Location_Size'=>'Large Planet / Vehicle (Terran Trade Federation Capitolship)'),
  array('Yarn'=>24,'Chi'=>177, 'Extend_Duration'=>'A Geological Age (~37,000,000 Years', 'Limit_Duration'=>'2 Secs / 1 Ordeal Phase', 'Group_Size'=>'A Billion / Trillion (<1,000,000,000,000)', 'Smaller_Size'=>'Neutrino Size (~ 1 yoctometre / 1.0 &times;10<sup>-27</sup>metres)','Location_Size'=>'A Ringworld or Mini-system (Jovian Moons) / Vehicle (VIC Solar Eclipse)'),
  array('Yarn'=>25,'Chi'=>190, 'Extend_Duration'=>'A Galactic Revolution (~230,000,000 Years)', 'Limit_Duration'=>'1 Sec / 2 Actions', 'Group_Size'=>'Billions / Trillions (<1,000,000,000,000,000)', 'Smaller_Size'=>'(~1.0 &times;10<sup>-28</sup>metres)','Location_Size'=>'A Solar System (or Dyson Sphere) / Vehicle (VIC Total Eclipse)'),
  array('Yarn'=>26,'Chi'=>203, 'Extend_Duration'=>'A Billion Years', 'Limit_Duration'=>'1 Action', 'Group_Size'=>'Trillions / Quintillions (1,000,000,000,000,000,000,000+)', 'Smaller_Size'=>'(~1.0 &times;10<sup>-29</sup>metres)','Location_Size'=>'Multi-stellar System, Parsecs of Space'),
  array('Yarn'=>27,'Chi'=>216, 'Extend_Duration'=>'A few Billion Years', 'Limit_Duration'=>'Half Action', 'Group_Size'=>'Entire Population', 'Smaller_Size'=>'(~1.0 &times;10<sup>-30</sup>metres)','Location_Size'=>'Interstellar Empire'),
  array('Yarn'=>28,'Chi'=>230,  'Extend_Duration'=>'Several Billion Years', 'Limit_Duration'=>'Microseconds', 'Group_Size'=>'Entire Populations / Species','Smaller_Size'=>'(~1.0 &times;10<sup>-31</sup>metres)','Location_Size'=>'Galaxy'),
  array('Yarn'=>29, 'Chi'=>244, 'Extend_Duration'=>'Almost as old as the Universe.', 'Limit_Duration'=>'Nanoseconds', 'Group_Size'=>'Most Individuals','Smaller_Size'=>'(~1.0 &times;10<sup>-32</sup>metres)','Location_Size'=>'InterGalactic / Galactic Cluster'),
  array('Yarn'=>30, 'Chi'=>259,  'Extend_Duration'=>'Current Age of the Universe', 'Limit_Duration'=>'Nevertime Duration', 'Group_Size'=>'Almost All (at least 90%)','Smaller_Size'=>'String theory 1- dimensional String length (~1.0 &times;10<sup>-33</sup>metres)','Location_Size'=>'Known Space / Visible Universe'),
  array('Yarn'=>31, 'Chi'=>274, 'Extend_Duration'=>'Older Than Time', 'Limit_Duration'=>'Instantaneous', 'Group_Size'=>'All bar a few (99.9999%)', 'Smaller_Size'=>'(~1.0 &times;10<sup>-34</sup>metres)','Location_Size'=>'Whole Universe'),
  array('Yarn'=>32, 'Chi'=>289, 'Extend_Duration'=>'Eternity', 'Limit_Duration'=>'Reversing time', 'Group_Size'=>'All', 'Smaller_Size'=>'Planck Length (1.6 &times;10<sup>-35</sup>metres)','Location_Size'=>'Local Multiverse'),
  array('Yarn'=>33, 'Chi'=>305, 'Extend_Duration'=>'All Alternate Histories and Futures', 'Limit_Duration'=>'Travelling in Time', 'Group_Size'=>'All and All Alternates','Smaller_Size'=>'Singularity','Location_Size'=>'Local Omniverse'),
  array('Yarn'=>34, 'Chi'=>321, 'Extend_Duration'=>'All Alternate Histories, Futures and Presents', 'Limit_Duration'=>'All Time Simultaneously', 'Group_Size'=>'All and All Alternates','Smaller_Size'=>'Sub-Singularity (imaginary space)','Location_Size'=>'Omniverse')
