static public function costTable($aspects){
  $aspects=explode(" ", $aspects);
  
  $ret = '<div class="t13ne-tablewrap"><table class="t13ne-table t13ne-cost-table"><thead><tr>';
  foreach($aspects as $aspect){
    $daspect=str_ireplace("_", " ", $aspect);
    $ret.="<th>{$daspect}</th>";
    if (!T13Types::contains($aspect,'Size')){
      $ret.='<th>Description</th>';
    }
  }
  // $ret.="<th>Tao Banal</th><th>Intrepid</th><th>Chi Bold</th><th>Yarn</th><th>Twists</th></tr></thead><tbody>";
  $ret.="<th>Chi Bold</th></tr></thead><tbody>";
  foreach ($aspects as $aspect){
    //$ret .="<tr><td>{$aspect} searching...</td></tr>";
    $arr = array_key_exists($aspect,self::$sway[0]);
    //$ret .="<tr><td>aspect {$arr} found</td></tr>";
    if (!$arr){
      //$ret .="<tr><td>{$aspect} found</td></tr>";
      foreach(self::$types as $styp){
        if (T13Types::contains( $styp['Element_Type'],$aspect)){    
        $cc = $styp['Chi']; 
        $type = $styp['Type']; 
        $desc = $styp['Sway_Type_Description'];
        if ($type!==''){
           $ret.="<tr><td class=\"t13ne-cost-content\">{$type}</td><td class=\"t13ne-description\">{$desc}</td><td class=\"t13ne-cost\">{$cc}</td></tr>";
        }
       
      }
    }
        //$cbanal = T13Boons::getBoonValue($cc);
        //$cint = 2*$cc;
        //$cy = T13Boons::getBoonReduced($cc,0);
        //$ct =  T13Boons::getBoonReduced($cy,1);
        //$ret.="<tr><td>{$styp['Type']}</td><td>{$styp['Sway_Type_Description']}</td><td>{$cbanal}</td><td>{$cint}</td><td>{$cc}</td><td>{$cy}</td><td>{$ct}</td></tr>";
       
    }else{
      //$ret .='<tr><td>type not found</td></tr>';
        foreach (self::$sway as $swa){
          $cc =$swa['Chi'];
          $type= $swa[$aspect]; 
          if ($type!==""){
            $ret.="<tr><td class=\"t13ne-cost-content\">{$type}</td><td class=\"t13ne-cost\">{$cc}</td></tr>";
          }
         
        }
      }
 }
  
  
  $ret.="</tbody><tfoot><tr>";
  foreach($aspects as $aspect){
    $daspect=str_ireplace("_", " ", $aspect);
    $ret.="<td>{$daspect}</td>";
    if (!T13Types::contains($aspect,'Size')){
    $ret.='<td>Description</td>';
    }
  }
 // $ret.='<td>Banal</td><td>Intrepid</td><td>Chi Bold</td><td>Yarn</td><td>Twists</td></tr></tfoot></table></div>';
 $ret.='<td>Chi Bold</td></tr></tfoot></table></div>';
  return $ret;
}

  static public function swayTable($passedtype){
    
    $ret='<div class="t13ne-tablewrap"><table class="t13ne-table t13ne-sway-table"><colgroup class="t13ne-sway-cols"><col class="t13ne-twists"><col class="t13ne-yarn"><col class="t13ne-chi"></colgroup><colgroup class="t13ne-durations"><col class="t13ne-extend"><col class="t13ne-limit"></colgroup><colgroup class="t13ne-size"><col class="t13ne-group"><col class="t13ne-smaller"><col class="t13ne-location"></colgroup><colgroup class="t13ne-sway"><col class="t13ne-sway"></colgroup><thead><tr><th class="t13ne-twists" rowspan="2">Twists / Shocks</th><th class="t13ne-yarn" rowspan="2">Yarn / Strains<br/> Monstrous</th><th class="t13ne-chi t13ne-sway-bold" rowspan="2">Chi / Stress<br/> Bold / Pips</th><th class="t13ne-sway-intrepid" rowspan="2">Facet Sway / <br/>Intrepid </th><th class="t13ne-sway-tao" rowspan="2">Tao Sway /<br/> Banal </th><th class="t13ne-duration" colspan="2">Duration</th><th class="t13ne-size" colspan="3">Size</th><th class="t13ne-types" rowspan="2">Additional Information</th></tr><tr><th class="t13ne-extend">Extend</th><th class="t13ne-limit"> Limit</th><th class="t13ne-group">Group</th><th class="t13ne-smaller">Small Sizes</th><th class="t13ne-location">Location</th></tr></thead><tbody>';
    $max=count(self::$sway);
    for ($i=0;$i<$max;$i++){
      $chi=self::$sway[$i]['Chi'];
      $ret.='<tr><td class="t13ne-twists">'.T13Boons::getBoonReduced(self::$sway[$i]['Yarn'],1).'</td>';
      $ret.='<td class="t13ne-yarn">'.self::$sway[$i]['Yarn'].'</td>';
      $ret.='<td class="t13ne-chi t13ne-sway-bold">'.$chi.'</td>';
       $ret.='<td class="t13ne-sway-intrepid">'. 2*$chi.' </td>';
      $lo=T13Boons::getBoonValue($chi);
       $ret.='<td class="t13ne-sway-tao">'. $lo. '</td>';
      $ret.='<td class="t13ne-extend">'.self::$sway[$i]['Extend_Duration'].'</td>';
      $ret.='<td class="t13ne-lmit">'.self::$sway[$i]['Limit_Duration'].'</td>';
      $ret.='<td class="t13ne-group">'.self::$sway[$i]['Group_Size'].'</td>';
       $ret.='<td class="t13ne-smaller">'.self::$sway[$i]['Smaller_Size'].'</td>';
      $ret.='<td class="t13ne-location">'.self::$sway[$i]['Location_Size'].'</td>';
      $ret.='<td class="t13ne-type">'.self::elementTypeSway($chi,$passedtype).'</td>';
     //$ret.='<td class="t13ne-sway-intrepid">'. 2*$chi.' </td>';
     //$lo=T13Boons::getBoonValue($chi);
       $ret.='</tr>';
    }
    $ret.='</tbody><tfoot><tr><td class="t13ne-twists">Twists / Shocks</td><td class="t13ne-yarn">Yarn / Strains<br/> Monstrous <br/></td><td class="t13ne-chi">Chi / Stress<br/> Bold / <br/> Pips</td><td class="t13ne-sway-intrepid">Facet Sway / <br/> Intrepid </td><td class="t13ne-sway-tao">Tao Sway /<br/> Banal </td><td class="t13ne-extend">Extend Duration</td><td class="t13ne-limit">Limit Duration</td><td class="t13ne-group">Group Size</td><td class="t13ne-smaller">Small Sizes</td><td class="t13ne-location">Location Size</td><td class="t13ne-type">Additional Information</td></tr></tfoot></table></div>';
    return $ret;
  }
  static public function elementTypeSway($chi, $type=""){
    
    $max=count(self::$types);
    $ret="";
    for ($i=0;$i<$max;$i++){
      $chib=self::$types[$i]['Chi'];
      $typeb=self::$types[$i]['Element_Type'];
     // echo ($type.$typeb);
      if ($chi==$chib&&(($type=='')||(mb_strtolower($type)==mb_strtolower($typeb))||(strtolower($type)==strtolower($typeb)))){
        $ret.='<details class="t13ne-info"><summary><span class="t13ne-etype">'.$typeb.'</span> — ';
        $ret.='<span class="t13ne-type">'.self::$types[$i]['Type'].'</span></summary> ';
        $ret.='<span class="t13ne-swaydescription">'.self::$types[$i]['Sway_Type_Description'].'</span></details>';
      }
    }
    return $ret;
  }
  static public function getSwayByGroupSize($number){
    $thisway=0;
     
     foreach(self::$sway as $swa){
      if (is_numeric($number)){
         $numb=intval($swa['Group_Size']);
         if ($number<=$numb){
            $thisway=$swa;
         }elseif ($number>=$numb){
          return $thisway;
         }
      }
      if ($number==$swa['Group_Size']){
        return $swa;
      }
     }
  }
  static public function getType($type=""){
     
    foreach (self::$types as $typ){
      if (strtolower($typ)==strtolower($type)){
        return $typ;
        break;
      }
    }
  }
  static public function getSwayForType($typi){
     
    if (is_string($typi)){
      foreach (self::$types as $type){
        foreach ($type as $key=>$val){
          if (strtolower($typi)==strtolower($val)){return $type;}elseif (T13Types::contains(strtolower($val),strtolower($typi))){return $type;}
        }
      }
    }
    if (is_array($typi)){
      foreach (self::$types as $type){
        foreach($type as $key=>$val){
          if ($type[$key]==$val){
            return $type;
          }
        }
      }
    }
  }
  static public function getSwayArray($columns=0){
   
    //array('Yarn'=>0,'Chi'=>0, 'Extend_Duration'=>'Instant','Limit_Duration'=>'Forever', 'Group_Size'=>'An Individual (1)', 'Smaller_Size'=>'','Location_Size'=>'A single individual or point target.'),
    if ($columns==0){$columns=array('Yarn','Chi', 'Extend_Duration','Limit_Duration', 'Group_Size', 'Location_Size');}
    if (is_string($columns)){$columns=explode(',', $columns);}
     return array_intersect_key(self::$sway, array_flip($columns));
  }
  static public function searchSway($search=0){
    
    //array('Yarn'=>0,'Chi'=>0, 'Extend_Duration'=>'Instant','Limit_Duration'=>'Forever', 'Group_Size'=>'An Individual (1)', 'Smaller_Size'=>'','Location_Size'=>'A single individual or point target.'),
    $ret=-1;
    if ($search==0){$search=array('Yarn'=>true,'Chi'=>true, 'Extend_Duration'=>true,'Limit_Duration'=>true, 'Group_Size'=>true, 'Smaller_Size'=>'','Location_Size'=>true);}
    $sc=count($search);
    foreach(self::$sway as $row){
      $r=array_filter($row,function($val, $key)use($search){return isset($search[$key])&&($search[$key]===true||$search[$key]===$val);},ARRAY_FILTER_USE_BOTH);
      if (count($r)==$sc){$ret=$r;break;}
    }
     return $ret;
  }
  static public function getFromSwayTable($swaya,$chi='',$yarn='', $type=''){
     
     if (is_string($swaya)){$type = $swaya;}
     foreach(self::$sway as $swa){
      if (($swa['Sway']==$swaya)||($swa['Chi']==$chi)||($swa['Yarn']==$yarn)||(strtolower($swa['Type'])==strtolower($type))){
        return $swa;
      }
     }
  }
